css:
color-scheme: dark;
  --app-bg: #060a0c;
  --app-surface: rgba(180, 255, 240, 0.028);
  --app-surface-hover: rgba(180, 255, 240, 0.045);
  --app-border: rgba(180, 255, 240, 0.07);
  --app-border-strong: rgba(180, 255, 240, 0.12);
  --app-text: #ecf8f5;
  --app-text-muted: #7f9691;
  --app-accent: #6ee7cf;
  --app-accent-soft: rgba(110, 231, 207, 0.14);
  --app-accent-border: rgba(110, 231, 207, 0.3);
  --app-accent-nav: rgba(110, 231, 207, 0.1);
  --app-elevated: #0a1012;
  --app-glow-1: rgba(45, 212, 191, 0.16);
  --app-glow-2: rgba(52, 211, 153, 0.1);
  --app-card-shadow: 0 20px 40px rgba(0, 0, 0, 0.52), inset 0 1px 0 rgba(180, 255, 240, 0.08), inset 0 -1px 0 rgba(0, 0, 0, 0.42);
  --app-sidebar-bg: radial-gradient(circle at 14% -3%, var(--app-glow-1), transparent 42%), radial-gradient(circle at 88% 106%, var(--app-glow-2), transparent 40%), var(--app-bg);
  --app-shell-bg: var(--app-sidebar-bg);
  --media-snake-1: rgba(45, 180, 160, 0.14);
  --media-snake-2: rgba(94, 234, 212, 0.58);
  --media-snake-3: rgba(204, 251, 241, 0.96);
  --media-snake-4: rgba(52, 211, 153, 0.72);
  --bg-primary: var(--app-bg);
  --bg-secondary: var(--app-elevated);
  --bg-elevated: #0e1518;
  --bg-glass: rgba(8, 14, 16, 0.86);
  --text-primary: var(--app-text);
  --text-secondary: var(--app-text-muted);
  --text-tertiary: rgba(127, 150, 145, 0.72);
  --accent: var(--app-accent);
  --accent-blue: var(--app-accent);
  --focus-glow: rgba(110, 231, 207, 0.22);
